// Import required modules
import { fetch } from '@cloudflare/durableobjects-fetch-handler';
import { Next } from 'next';

// Set up environment variables
const SENDGRID_API_KEY = Deno.env.get('SENDGRID_API_KEY');
const STRIPE_SECRET_KEY = Deno.env.get('STRIPE_SECRET_KEY');

// Define a function to send email using SendGrid API
async function sendEmail(to, subject, body) {
  const response = await fetch(`https://api.sendgrid.com/v3/mail/send`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${SENDGRID_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email: to }]
        }
      ],
      from: { email: 'your-email@example.com' },
      subject,
      content: [
        {
          type: 'text/plain',
          value: body
        }
      ]
    })
  });

  if (response.ok) {
    return true;
  } else {
    throw new Error(`Failed to send email: ${response.statusText}`);
  }
}

// Define a function to process payment using Stripe API
async function processPayment(amount, currency, source) {
  const response = await fetch('https://api.stripe.com/v1/charges', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      amount,
      currency,
      source
    })
  });

  if (response.ok) {
    return response.json();
  } else {
    throw new Error(`Failed to process payment: ${response.statusText}`);
  }
}

// Define the Cloudflare Worker function
async function handleRequest(request, env, ctx) {
  try {
    // Handle API authentication and error handling
    const authHeader = request.headers.get('Authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return new Response(`Unauthorized: Missing or invalid Authorization header`, { status: 401 });
    }

    const token = authHeader.substring(7);
    if (token !== SENDGRID_API_KEY && token !== STRIPE_SECRET_KEY) {
      return new Response(`Unauthorized: Invalid token`, { status: 401 });
    }

    // Handle API requests
    switch (request.method) {
      case 'POST':
        const body = await request.json();
        if (body.type === 'email') {
          const result = await sendEmail(body.to, body.subject, body.body);
          return new Response(`Email sent successfully`, { status: 200 });
        } else if (body.type === 'payment') {
          const result = await processPayment(body.amount, body.currency, body.source);
          return new Response(JSON.stringify(result), { status: 200 });
        }
        break;
      default:
        return new Response(`Method not allowed`, { status: 405 });
    }

    // Handle errors
  } catch (error) {
    console.error(error);
    return new Response(`Internal Server Error`, { status: 500 });
  }
}

// Export the Cloudflare Worker function
export async function fetchHandler(request, env, ctx) {
  return handleRequest(request, env, ctx);
}